                border: Border.all(
                  color: activeExperiment.accent.withValues(alpha: 0.16),
                ),
              ),
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  Text(
                    'Lab Note',
                    style: theme.textTheme.labelMedium?.copyWith(
                      color: activeExperiment.accent,
                    ),
                  ),
                  const SizedBox(height: 8),
