                ),
              ),
              Positioned(
                left: imageX - 36,
                top: constraints.maxHeight * 0.45,
                child: Transform.scale(
                  scaleX: -1,
                  child: const Text(
                    'AMBULANCE',
                    style: TextStyle(
                      fontWeight: FontWeight.w700,
                      color: Color(0xFF0F766E),
                    ),
                  ),
                ),
              ),
              Positioned(
                left: objectX,
                bottom: 24,
                child: const Icon(
                  Icons.person,
                  size: 42,
                  color: Color(0xFF1D4ED8),
                ),
              ),
              Positioned(
                left: imageX,
                bottom: 24,
                child: Transform.scale(
                  scaleX: -1,
                  child: const Icon(
                    Icons.person,
                    size: 42,
                    color: Color(0xFF059669),
                  ),
                ),
              ),
            ],
          );
        },
      ),
    );
