  Future<void> _askSphericalMirrorAi() async {
    setState(() {
      _sphereAiLoading = true;
      _sphereAiError = null;
    });

    try {
      final response = await _aiTutorService.getTutorResponse(
        const AiTutorRequest(
          classId: '7',
          experimentId: 'spherical_mirror',
