  void _updateDiscSpeed() {
    final level = _newtonSpeedLevel.round().clamp(0, 3);
    final durations = <int>[1800, 900, 420, 180];
    final millis = durations[level];
    _discController.duration = Duration(milliseconds: millis);
    _discController
      ..reset()
      ..repeat();
  }

